	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusForbidden)
	}))
	defer srv.Close()

	items := &mockItemService{}
	w := &PageFetchWorker{
		Items:  items,
		Client: srv.Client(),
	}

	job := &river.Job[PageFetchArgs]{
		Args: PageFetchArgs{
			ItemID: uuid.New(),
			URL:    srv.URL + "/secret",
		},
	}

	err := w.Work(context.Background(), job)
	if err == nil {
		t.Fatal("Work() should return error for 403")
	}

	// Verify error wrapping includes context
	errMsg := err.Error()
	if !strings.Contains(errMsg, "page_fetch") {
		t.Errorf("error should contain 'page_fetch', got: %s", errMsg)
	}
	if !strings.Contains(errMsg, "403") {
		t.Errorf("error should contain status code '403', got: %s", errMsg)
	}

	// Verify item was marked as error
	if len(items.updates) < 2 {
		t.Fatalf("expected at least 2 updates, got %d", len(items.updates))
	}
	if items.updates[0].Status != "processing" {
		t.Errorf("first status = %q, want %q", items.updates[0].Status, "processing")
	}
	if items.updates[1].Status != "error" {
		t.Errorf("second status = %q, want %q", items.updates[1].Status, "error")
	}
}

